  public String getPoolUsageMin(){
    long memoryUnit=1024L*1024L;//M
    String memoryUnitString="M";
//    if(Runtime.getRuntime().totalMemory()<3L*1024L*1024L*1024L){
//      memoryUnit=memoryUnit/1024L;
//      memoryUnitString="M";
//    }

    List<MemoryPoolMXBean> list = ManagementFactory.getPlatformMXBeans(MemoryPoolMXBean.class);
    String result="";
    for(MemoryPoolMXBean b:list){
      String poolName=b.getName();
      MemoryUsage usage=b.getCollectionUsage();//getCollectionUsage is the usage after GC
      if(usage==null) continue;
      long used=usage.getUsed();
      long max=usage.getMax();
      long percent=(used)*100L/max;
      if(max<1024L) result+=poolName+": "+((used)/memoryUnit+memoryUnitString)+"<br>";
      else result+=poolName+": "+((used)/memoryUnit+memoryUnitString)+"/"+(max/memoryUnit+memoryUnitString)+" ("+percent+"%)<br>";
    }
    return result;
  }
