      EnvironmentStats stat=env.getStats(ss);
      long size=stat.getCacheTotalBytes();
      long sizeM=size/(1024L*1024L);//M
      totalSize+=size;

      long cacheTotal=stat.getNLNsFetch()+stat.getNBINsFetch();
      long cacheMiss=stat.getNLNsFetchMiss()+stat.getNBINsFetchMiss();//not available in dbv4 +stat.getNFullBINsMiss();
      long criticalEvict=0L;
      if(JEVersion.CURRENT_VERSION.getMajor()>4){
        Method method=EnvironmentStats.class.getMethod("getNBytesEvictedCritical");
        if(method!=null){
          criticalEvict=(Long)method.invoke(stat);
          criticalEvict=criticalEvict/Const.MB_SIZE;
        }
      }
      else{
        criticalEvict=(stat.getNBINsEvictedCritical()+stat.getNUpperINsEvictedCritical())/Const.MB_SIZE;
      }
      double hitRate=100*cacheMiss/cacheTotal;
      String statString=Encoder.formatNumber(hitRate,"#")+"%";
      //statString=stat.getNLNsFetchMiss()+"/"+stat.getNLNsFetch()+","+stat.getNBINsFetchMiss()+"/"+stat.getNBINsFetch()+","+stat.getNFullBINsMiss();

